type FileTreeService interface {
	// 获取文件树（一期功能）
	// 返回指定路径的文件和目录列表
	GetFileTree(ctx context.Context, req *GetFileTreeRequest) (r *v1.Response, err error)
	// 下载文件（一期功能）
	// 返回文件内容（二进制流）
	// 注意：这个接口返回的不是标准的 base.Response，而是直接返回文件流
	DownloadFile(ctx context.Context, req *DownloadFileRequest) (r *v1.Response, err error)
	// 获取文件统计信息（一期功能）
	// 返回文件树的统计数据
	GetFileStats(ctx context.Context, req *GetFileTreeRequest) (r *v1.Response, err error)
	// 批量获取文件信息
	// 根据路径列表返回对应的文件信息（用于报告关联文件查询）
	GetFilesByPaths(ctx context.Context, req *GetFilesByPathsRequest) (r *v1.Response, err error)
	// 上传文件（二期功能 - 仅管理员）
	UploadFile(ctx context.Context, req *UploadFileRequest) (r *v1.Response, err error)
	// 删除文件/目录（二期功能 - 仅管理员）
	DeleteFile(ctx context.Context, req *DeleteFileRequest) (r *v1.Response, err error)
	// 创建目录（二期功能 - 仅管理员）
	CreateDir(ctx context.Context, req *CreateDirRequest) (r *v1.Response, err error)
}

